const $ = (selector, root=document) => root.querySelector(selector);
const $$ = (selector, root=document) => [...root.querySelectorAll(selector)];
const SECTION_ORDER = ['W','U','B','R','G','M','C','L'];
const SECTION_LABELS = {W:'White', U:'Blue', B:'Black', R:'Red', G:'Green', M:'Multicolour', C:'Colourless', L:'Lands'};
const RARITY_LABELS = {C:'Common', U:'Uncommon', R:'Rare', M:'Mythic'};
let activeSection = 'all';
let query = '';
let siteData = window.CARDFORGE_SITE;

function escapeHtml(value) {
  const el = document.createElement('span');
  el.textContent = value == null ? '' : String(value);
  return el.innerHTML;
}

function imageMarkup(card) {
  if (card.artwork_path) {
    return `<img src="./${card.artwork_path}" alt="${escapeHtml(card.name)}" loading="lazy">`;
  }
  return `<div class="placeholder"><span>${escapeHtml(card.name)}<br><small>Artwork coming soon</small></span></div>`;
}

function cardMarkup(card) {
  const stats = card.loyalty || (card.power !== null && card.toughness !== null && card.power !== undefined && card.toughness !== undefined ? `${card.power}/${card.toughness}` : '');
  return `<article class="card-tile" data-number="${card.collector_number}">
    <div class="card-art">${imageMarkup(card)}</div>
    <div class="card-meta">
      <strong>${escapeHtml(card.name)}</strong>
      <small>${String(card.collector_number).padStart(3, '0')} / ${siteData.set.target_size || siteData.summary.cards}${stats ? ` · ${escapeHtml(stats)}` : ''}</small>
      <small>${escapeHtml(card.type_line)} · ${RARITY_LABELS[card.rarity] || card.rarity}</small>
    </div>
  </article>`;
}

function showModal(card) {
  const modal = $('#modal');
  const download = $('#modal-download');
  $('#modal-name').textContent = card.name;
  $('#modal-type').textContent = `${card.mana_cost || ''}${card.mana_cost && card.type_line ? ' · ' : ''}${card.type_line} · ${RARITY_LABELS[card.rarity] || card.rarity}`;
  $('#modal-rules').textContent = [card.oracle_text || '', card.flavour_text ? `

${card.flavour_text}` : ''].join('').trim() || 'No rules text.';
  $('#modal-image').innerHTML = imageMarkup(card);
  if (card.artwork_path) {
    download.href = `./${card.artwork_path}`;
    download.download = `${String(card.collector_number).padStart(3, '0')}-${card.name.replace(/[^a-z0-9]+/gi, '-').replace(/^-|-$/g, '')}.png`;
    download.classList.remove('hidden');
  } else {
    download.classList.add('hidden');
  }
  modal.classList.remove('hidden');
  document.body.style.overflow = 'hidden';
}

function renderGallery(cards) {
  const gallery = $('#gallery');
  const actions = $('#section-actions');
  const filtered = cards.filter(card => {
    const matchesSection = activeSection === 'all' || card.colour_section === activeSection;
    const haystack = `${card.name} ${card.type_line} ${card.oracle_text}`.toLowerCase();
    return matchesSection && (!query || haystack.includes(query));
  });
  const available = SECTION_ORDER.filter(section => cards.some(card => card.colour_section === section));
  actions.innerHTML = ['all', ...available].map(section => `<button class="filter ${activeSection === section ? 'active' : ''}" type="button" data-filter="${section}">${section === 'all' ? 'All cards' : SECTION_LABELS[section]}</button>`).join('');
  $$('[data-filter]', actions).forEach(button => button.onclick = () => {
    activeSection = button.dataset.filter;
    renderGallery(cards);
  });
  const sections = SECTION_ORDER.map(section => {
    const items = filtered.filter(card => card.colour_section === section);
    return items.length ? {section, items} : null;
  }).filter(Boolean);
  $('#gallery-count').textContent = `${filtered.length} card${filtered.length === 1 ? '' : 's'} on display`;
  gallery.innerHTML = sections.map(({section, items}) => `<section class="colour-group" data-section="${section}">
    <div class="colour-group-head"><h3>${SECTION_LABELS[section]}</h3><span>${items.length} cards</span></div>
    <div class="card-grid">${items.map(cardMarkup).join('')}</div>
  </section>`).join('') || '<div class="placeholder">No cards match your search.</div>';
  $$('[data-number]', gallery).forEach(tile => {
    tile.onclick = () => {
      const number = Number(tile.dataset.number);
      const card = cards.find(item => item.collector_number === number);
      if (card) showModal(card);
    };
  });
}

function loadSite() {
  const data = siteData;
  if (!data) throw new Error('The set data was not included in this export.');
  document.title = `Magic: The Gathering — ${data.set.title || 'The Boys'}`;
  $('#site-title').textContent = data.set.title || 'Cardforge';
  const isTheBoys = (data.set.title || '').trim().toLowerCase() === 'the boys';
  const heroCopy = isTheBoys
    ? `Every friendship has its legends. This one has ${data.summary.cards} of them.`
    : (data.set.premise || 'An unforgettable custom set built from friendship, shared stories, and questionable decisions.');
  const storyCopy = isTheBoys
    ? 'A celebration of the trips, in-jokes, late nights, and increasingly unlikely stories that made The Boys legendary. Familiar faces become creatures, shared memories become spells, and notable places return as lands—ready to be drafted, played, and argued over.'
    : (data.set.premise || heroCopy);
  $('#site-premise').textContent = heroCopy;
  $('#set-story').textContent = storyCopy;
  const finished = data.cards.filter(card => card.artwork_path);
  const feature = finished.find(card => card.rarity === 'M') || finished.find(card => card.rarity === 'R') || finished[0];
  $('#hero-card').innerHTML = feature ? imageMarkup(feature) : '';
  $('#hero-facts').innerHTML = [
    {value:data.summary.cards,label:'Cards'},
    {value:(data.balance.archetypes || []).length,label:'Draft archetypes'},
    {value:data.set.code || 'TBY',label:'Set code'}
  ].map(item => `<div class="fact"><strong>${item.value}</strong><span>${item.label}</span></div>`).join('');
  const mechanics = (data.balance.design_elements || []).filter(row => row.kind === 'returning_mechanic');
  $('#mechanic-list').innerHTML = mechanics.map(row => `<span>${escapeHtml(row.name)}</span>`).join('');
  const archetypes = $('#archetypes');
  archetypes.innerHTML = (data.balance.archetypes || []).map(row => `<article class="archetype" data-pair="${escapeHtml(row.colour_pair)}"><span class="archetype-pair">${escapeHtml(row.colour_pair)}</span><strong>${escapeHtml(row.name)}</strong><small>${escapeHtml(row.description || '')}</small></article>`).join('');
  renderGallery(data.cards || []);
}

$('#card-search').addEventListener('input', event => {
  query = event.target.value.trim().toLowerCase();
  renderGallery(siteData.cards || []);
});
$('#modal').onclick = event => {
  if (event.target.matches('[data-close-modal], .modal-backdrop')) {
    $('#modal').classList.add('hidden');
    document.body.style.overflow = '';
  }
};
document.addEventListener('keydown', event => {
  if (event.key === 'Escape') { $('#modal').classList.add('hidden'); document.body.style.overflow = ''; }
});
try { loadSite(); } catch (err) { $('#site-premise').textContent = err.message; }
